#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* left;
    Node* right;
    Node(int x) {
        data = x;
        left = right = NULL;
    }
};

bool findNode(Node* root, int key) {
    if (root == NULL) return false;
    if (root->data == key) return true;
    return findNode(root->left, key) || findNode(root->right, key);
}

Node* findLCA(Node* root, int n1, int n2) {
    if (root == NULL) return NULL;

    if (root->data == n1 || root->data == n2)
        return root;

    Node* leftLCA = findLCA(root->left, n1, n2);
    Node* rightLCA = findLCA(root->right, n1, n2);

    if (leftLCA && rightLCA) return root;

    return (leftLCA != NULL) ? leftLCA : rightLCA;
}

Node* buildTree(vector<int>& arr) {
    if (arr.empty() || arr[0] == -1) return NULL;

    queue<Node*> q;
    Node* root = new Node(arr[0]);
    q.push(root);

    for(int i = 1; i < arr.size(); i += 2) {
        Node* current = q.front();
        q.pop();

        if (i < arr.size() && arr[i] != -1) {
            current->left = new Node(arr[i]);
            q.push(current->left);
        }

        if (i+1 < arr.size() && arr[i+1] != -1) {
            current->right = new Node(arr[i+1]);
            q.push(current->right);
        }
    }
    return root;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> arr(n);
        for(int i = 0; i < n; i++) {
            cin >> arr[i];
        }

        int n1, n2;
        cin >> n1 >> n2;

        Node* root = buildTree(arr);

        if (!findNode(root, n1) || !findNode(root, n2)) {
            cout << "-1" << endl;
            continue;
        }

        Node* lca = findLCA(root, n1, n2);
        cout << lca->data << endl;
    }
    return 0;
}

