#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node *left, *right;
} Node;

typedef struct QNode {
    Node* node;
    struct QNode* next;
} QNode;

typedef struct {
    QNode *front, *rear;
} Queue;

void q_init(Queue* q){ q->front = q->rear = NULL; }
int q_empty(Queue* q){ return q->front == NULL; }
void q_push(Queue* q, Node* n){
    QNode* x = (QNode*)malloc(sizeof(QNode));
    x->node = n; x->next = NULL;
    if(q->rear) q->rear->next = x; else q->front = x;
    q->rear = x;
}
Node* q_pop(Queue* q){
    if(q_empty(q)) return NULL;
    QNode* x = q->front;
    Node* n = x->node;
    q->front = x->next;
    if(!q->front) q->rear = NULL;
    free(x);
    return n;
}

Node* newNode(int v){
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = v; n->left = n->right = NULL;
    return n;
}

int findNode(Node* root, int key){
    if(!root) return 0;
    if(root->data == key) return 1;
    return findNode(root->left, key) || findNode(root->right, key);
}

Node* findLCA(Node* root, int n1, int n2){
    if(!root) return NULL;
    if(root->data == n1 || root->data == n2) return root;
    Node* L = findLCA(root->left, n1, n2);
    Node* R = findLCA(root->right, n1, n2);
    if(L && R) return root;
    return L ? L : R;
}

Node* buildTreeFromArray(int* arr, int n){
    if(n==0 || arr[0]==-1) return NULL;
    Queue q; q_init(&q);
    Node* root = newNode(arr[0]);
    q_push(&q, root);
    int i = 1;
    while(i < n && !q_empty(&q)){
        Node* cur = q_pop(&q);
        if(i < n && arr[i] != -1){
            cur->left = newNode(arr[i]);
            q_push(&q, cur->left);
        }
        i++;
        if(i < n && arr[i] != -1){
            cur->right = newNode(arr[i]);
            q_push(&q, cur->right);
        }
        i++;
    }
    while(!q_empty(&q)) q_pop(&q);
    return root;
}

void freeTree(Node* r){
    if(!r) return;
    freeTree(r->left);
    freeTree(r->right);
    free(r);
}

int main(void){
    int t;
    if(scanf("%d",&t)!=1) return 0;
    while(t--){
        int n;
        if(scanf("%d",&n)!=1) return 0;
        int* arr = (int*)malloc(sizeof(int)*n);
        for(int i=0;i<n;i++) scanf("%d",&arr[i]);
        int n1,n2; scanf("%d %d",&n1,&n2);

        Node* root = buildTreeFromArray(arr, n);

        if(!findNode(root, n1) || !findNode(root, n2)){
            printf("-1\n");
            freeTree(root);
            free(arr);
            continue;
        }

        Node* lca = findLCA(root, n1, n2);
        if(lca) printf("%d\n", lca->data);
        else printf("-1\n");

        freeTree(root);
        free(arr);
    }
    return 0;
}
